const express = require('express');
const crypto = require('crypto');

const app = express();
app.use(express.json());

// In-memory storage (replace with database in production)
const players = {};
const levelCompletions = {};
const claimedRewards = {};

// Level configuration
const LEVEL_CONFIG = {
  1: { maxTime: 120, starThresholds: [500, 1000, 2000], rewards: { coins: [10, 25, 50], gems: [0, 1, 3] } },
  2: { maxTime: 150, starThresholds: [800, 1500, 3000], rewards: { coins: [15, 30, 60], gems: [0, 2, 4] } },
  3: { maxTime: 180, starThresholds: [1000, 2000, 4000], rewards: { coins: [20, 40, 80], gems: [1, 3, 5] } },
  4: { maxTime: 200, starThresholds: [1200, 2500, 5000], rewards: { coins: [25, 50, 100], gems: [1, 4, 6] } },
  5: { maxTime: 240, starThresholds: [1500, 3000, 6000], rewards: { coins: [30, 60, 120], gems: [2, 5, 8] } },
};

// Milestone rewards (based on total stars earned)
const MILESTONE_REWARDS = {
  3: { coins: 100, gems: 5, item: 'bronze_chest' },
  6: { coins: 250, gems: 10, item: 'silver_chest' },
  10: { coins: 500, gems: 20, item: 'gold_chest' },
  15: { coins: 1000, gems: 50, item: 'diamond_chest' },
};

// Daily challenge config
const DAILY_CHALLENGE_REWARD = { coins: 200, gems: 10 };

// Helper: get or create player
function getOrCreatePlayer(playerId) {
  if (!players[playerId]) {
    players[playerId] = {
      id: playerId,
      coins: 0,
      gems: 0,
      items: [],
      totalStars: 0,
      levelsCompleted: {},
      createdAt: new Date().toISOString(),
      lastActive: new Date().toISOString(),
    };
    levelCompletions[playerId] = [];
    claimedRewards[playerId] = new Set();
  }
  players[playerId].lastActive = new Date().toISOString();
  return players[playerId];
}

// Helper: calculate stars based on score
function calculateStars(levelId, score) {
  const config = LEVEL_CONFIG[levelId];
  if (!config) return 0;

  let stars = 0;
  for (let i = 0; i < config.starThresholds.length; i++) {
    if (score >= config.starThresholds[i]) {
      stars = i + 1;
    }
  }
  return stars;
}

// Helper: calculate rewards for a level completion
function calculateRewards(levelId, stars) {
  const config = LEVEL_CONFIG[levelId];
  if (!config || stars <= 0) return { coins: 0, gems: 0 };

  const index = stars - 1;
  return {
    coins: config.rewards.coins[index] || 0,
    gems: config.rewards.gems[index] || 0,
  };
}

// Helper: basic validation for suspicious data
function validateCompletionData(levelId, score, timeTaken) {
  const errors = [];

  if (!LEVEL_CONFIG[levelId]) {
    errors.push(`Invalid level ID: ${levelId}`);
  }

  if (typeof score !== 'number' || score < 0 || score > 999999) {
    errors.push('Score must be a number between 0 and 999999');
  }

  if (typeof timeTaken !== 'number' || timeTaken < 0) {
    errors.push('Time taken must be a positive number');
  }

  const config = LEVEL_CONFIG[levelId];
  if (config && timeTaken < 3) {
    errors.push('Completion time suspiciously low');
  }

  if (config && timeTaken > config.maxTime * 10) {
    errors.push('Completion time exceeds maximum allowed');
  }

  // Flag suspiciously high scores (basic anti-cheat)
  if (config) {
    const maxReasonableScore = config.starThresholds[2] * 3;
    if (score > maxReasonableScore) {
      errors.push('Score exceeds reasonable maximum');
    }
  }

  return errors;
}

// Middleware: simple auth (in production, use JWT or similar)
function authenticate(req, res, next) {
  const playerId = req.headers['x-player-id'];
  if (!playerId || typeof playerId !== 'string' || playerId.length < 1) {
    return res.status(401).json({ error: 'Missing or invalid X-Player-Id header' });
  }
  req.playerId = playerId;
  next();
}

// POST /api/players/register - Register or get player
app.post('/api/players/register', (req, res) => {
  const { playerId } = req.body;

  if (!playerId || typeof playerId !== 'string') {
    return res.status(400).json({ error: 'playerId is required' });
  }

  const isNew = !players[playerId];
  const player = getOrCreatePlayer(playerId);

  res.status(isNew ? 201 : 200).json({
    success: true,
    message: isNew ? 'Player registered successfully' : 'Player already exists',
    player: {
      id: player.id,
      coins: player.coins,
      gems: player.gems,
      items: player.items,
      totalStars: player.totalStars,
      levelsCompleted: player.levelsCompleted,
    },
  });
});

// GET /api/players/profile - Get player profile
app.get('/api/players/profile', authenticate, (req, res) => {
  const player = getOrCreatePlayer(req.playerId);

  res.json({
    success: true,
    player: {
      id: player.id,
      coins: player.coins,
      gems: player.gems,
      items: player.items,
      totalStars: player.totalStars,
      levelsCompleted: player.levelsCompleted,
      createdAt: player.createdAt,
      lastActive: player.lastActive,
    },
  });
});

// POST /api/levels/:levelId/complete - Complete a level
app.post('/api/levels/:levelId/complete', authenticate, (req, res) => {
  const levelId = parseInt(req.params.levelId, 10);
  const { score, timeTaken, moves, combo } = req.body;

  // Validate input
  const validationErrors = validateCompletionData(levelId, score, timeTaken);
  if (validationErrors.length > 0) {
    return res.status(400).json({
      success: false,
      errors: validationErrors,
    });
  }

  const player = getOrCreatePlayer(req.playerId);

  // Check if player has unlocked this level (must complete previous levels)
  if (levelId > 1) {
    const previousLevel = levelId - 1;
    if (!player.levelsCompleted[previousLevel] || player.levelsCompleted[previousLevel].stars < 1) {
      return res.status(403).json({
        success: false,
        error: `Must complete level ${previousLevel} before attempting level ${levelId}`,
      });
    }
  }

  // Calculate stars and rewards
  const stars = calculateStars(levelId, score);

  if (stars === 0) {
    return res.status(200).json({
      success: true,
      passed: false,
      message: 'Level not passed. Score too low.',
      score,
      timeTaken,
      starsEarned: 0,
      rewards: { coins: 0, gems: 0 },
    });
  }

  const rewards = calculateRewards(levelId, stars);

  // Time bonus: extra coins for fast completion
  const config = LEVEL_CONFIG[levelId];
  let timeBonus = 0;
  if (timeTaken <= config.maxTime * 0.5) {
    timeBonus = Math.floor(rewards.coins * 0.5);
  } else if (timeTaken <= config.maxTime * 0.75) {
    timeBonus = Math.floor(rewards.coins * 0.25);
  }

  // Combo bonus
  let comboBonus = 0;
  if (typeof combo === 'number' && combo > 5) {
    comboBonus = Math.min(Math.floor(combo * 2), 100);
  }

  const totalCoins = rewards.coins + timeBonus + comboBonus;
  const totalGems = rewards.gems;

  // Check if this is a new best for the level
  const previousBest = player.levelsCompleted[levelId];
  const isNewBest = !previousBest || stars > previousBest.stars || score > previousBest.bestScore;
  const isFirstCompletion = !previousBest;

  // Only award incremental rewards if improving
  let awardedCoins = totalCoins;
  let awardedGems = totalGems;

  if (previousBest) {
    const previousRewards = calculateRewards(levelId, previousBest.stars);
    // Only award the difference if improving stars
    if (stars > previousBest.stars) {
      awardedCoins = totalCoins - previousRewards.coins;
      awardedGems = totalGems - previousRewards.gems;
    } else {
      // Replay reward: small percentage
      awardedCoins = Math.floor(totalCoins * 0.1);
      awardedGems = 0;
    }
  }

  // Update player data
  player.coins += Math.max(0, awardedCoins);
  player.gems += Math.max(0, awardedGems);

  // Update stars
  const previousStars = previousBest ? previousBest.stars : 0;
  const starDiff = Math.max(0, stars - previousStars);
  player.totalStars += starDiff;

  // Update level completion record
  player.levelsCompleted[levelId] = {
    stars: Math.max(stars, previousStars),
    bestScore: Math.max(score, previousBest ? previousBest.bestScore : 0),
    bestTime: previousBest ? Math.min(timeTaken, previousBest.bestTime) : timeTaken,
    completionCount: (previousBest ? previousBest.completionCount : 0) + 1,
    lastCompletedAt: new Date().toISOString(),
  };

  // Record completion history
  const completionId = crypto.randomUUID();
  const completionRecord = {
    id: completionId,
    playerId: req.playerId,
    levelId,
    score,
    timeTaken,
    moves: moves || null,
    combo: combo || null,
    stars,
    coinsAwarded: Math.max(0, awardedCoins),
    gemsAwarded: Math.max(0, awardedGems),
    timeBonus,
    comboBonus,
    isNewBest,
    isFirstCompletion,
    completedAt: new Date().toISOString(),
  };

  levelCompletions[req.playerId].push(completionRecord);

  // Check for newly unlocked milestones
  const newMilestones = [];
  for (const [threshold, reward] of Object.entries(MILESTONE_REWARDS)) {
    const thresholdNum = parseInt(threshold, 10);
    if (player.totalStars >= thresholdNum && player.totalStars - starDiff < thresholdNum) {
      newMilestones.push({
        threshold: thresholdNum,
        reward,
      });
    }
  }

  // Check if next level is unlocked
  const nextLevelId = levelId + 1;
  const nextLevelUnlocked = LEVEL_CONFIG[nextLevelId] && isFirstCompletion;

  res.status(200).json({
    success: true,
    passed: true,
    completionId,
    levelId,
    score,
    timeTaken,
    starsEarned: stars,
    isNewBest,
    isFirstCompletion,
    rewards: {
      coins: Math.max(0, awardedCoins),
      gems: Math.max(0, awardedGems),
      timeBonus,
      comboBonus,
    },
    playerState: {
      coins: player.coins,
      gems: player.gems,
      totalStars: player.totalStars,
    },
    levelState: player.levelsCompleted[levelId],
    nextLevelUnlocked: nextLevelUnlocked ? nextLevelId : null,
    newMilestones,
  });
});

